self.onInit = function () {

    var chartDom = document.getElementById('heatmap');
    self.chart = echarts.init(chartDom);

    self.chart.setOption({
        tooltip: {
            position: 'top',
            formatter: function (p) {
                return p.value[1] + " - " + p.value[0] + "h : " + p.value[2].toFixed(2);
            }
        },
        grid: {
            height: '80%',
            top: '10%'
        },
        xAxis: {
            type: 'category',
            name: 'Hour',
            data: []
        },
        yAxis: {
            type: 'category',
            name: 'Day',
            data: []
        },
        visualMap: {
            min: 0,
            max: 1,
            calculable: true,
            orient: 'horizontal',
            left: 'center',
            bottom: '5%',
            inRange: {
                color: [
                    '#313695',
                    '#4575b4',
                    '#74add1',
                    '#abd9e9',
                    '#e0f3f8',
                    '#ffffbf',
                    '#fee090',
                    '#fdae61',
                    '#f46d43',
                    '#d73027'
                ]
            }
        },
        series: [
            {
                type: 'heatmap',
                data: [],
                emphasis: {
                    itemStyle: {
                        borderColor: '#333',
                        borderWidth: 1
                    }
                }
            }
        ]
    });
};

self.onDataUpdated = function () {

    if (!self.ctx.data || !self.ctx.data.length) {
        return;
    }

    var points = self.ctx.data[0].data;

    if (!points || !points.length) {
        return;
    }

    var matrix = {};
    var days = new Set();

    var min = Infinity;
    var max = -Infinity;

    for (var i = 0; i < points.length; i++) {

        var ts = points[i][0];
        var value = parseFloat(points[i][1]);

        if (isNaN(value)) continue;

        var date = new Date(ts);

        var hour = date.getHours();
        var day = date.toISOString().slice(0, 10);

        days.add(day);

        if (!matrix[day]) matrix[day] = {};
        if (!matrix[day][hour]) matrix[day][hour] = [];

        matrix[day][hour].push(value);

        if (value < min) min = value;
        if (value > max) max = value;
    }

    var yLabels = Array.from(days).sort();

    var xLabels = [];
    for (var h = 0; h < 24; h++) {
        xLabels.push(h);
    }

    var heatmapData = [];

    for (var d = 0; d < yLabels.length; d++) {

        var day = yLabels[d];

        for (var h = 0; h < 24; h++) {

            if (matrix[day] && matrix[day][h]) {

                var arr = matrix[day][h];
                var sum = 0;

                for (var k = 0; k < arr.length; k++) {
                    sum += arr[k];
                }

                var avg = sum / arr.length;

                heatmapData.push([h, d, avg]);
            }
        }
    }

    if (!isFinite(min) || !isFinite(max) || min === max) {
        min = 0;
        max = 1;
    }

    self.chart.setOption({
        xAxis: {
            data: xLabels
        },
        yAxis: {
            data: yLabels
        },
        visualMap: {
            min: min,
            max: max
        },
        series: [
            {
                data: heatmapData
            }
        ]
    });

};

self.onResize = function () {
    if (self.chart) {
        self.chart.resize();
    }
};

self.onDestroy = function () {
    if (self.chart) {
        self.chart.dispose();
    }
};

